import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下午三點零三分。教室裡的時鐘走得很準，秒針每跳一格都發出很小的「嗒」聲，被窗外的雨聲蓋掉大半，但在安靜的間隙裡還是聽得到。顧言坐在教室最後一排靠窗的位置，面前攤著一本沒在看的書，手指無意識地轉著手機。手機螢幕是暗的，但他知道如果點開，那條訊息還在。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外的雨和早上不一樣了。早上的雨是斜的，風帶著它從一個方向打過來，打在玻璃上會發出規律的敲擊聲。現在的雨沒有方向。雨滴從天空垂直砸下來，密密麻麻，像有人在天上倒水。操場上的臨時舞台已經拉起了防水布，布面被雨打得鼓起來又塌下去，發出沉悶的、像心跳一樣的聲響。" },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "各位同學、老師、來賓，以下是一則緊急通知。請注意聽。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廣播的聲音從教室天花板的喇叭裡傳出來，帶著一層細微的電流雜音。聲音不大，但在雨聲的間隙裡顯得格外清晰，像一個人突然壓低了嗓子說話，所有人都會本能地安靜下來。" },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "中央氣象署剛剛發布最新颱風動態。颱風路徑較預測偏北，對本地區的影響將比先前預估更為顯著。預計傍晚起風雨增強，夜間可能達到豪雨等級。" },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "為確保安全，校方決定縮短今晚所有戶外活動時程。原定晚間八點開始的閉幕戶外表演，將提前至六點三十分於禮堂室內進行。各活動區域請於下午五點前完成場地整理。" },
    { characterId: CharacterId.Student, character: "同學", dialogue: "山路是不是也要封了？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "坐在前排的一個男生問了一句，聲音不大，像是自言自語，但教室裡夠安靜，每個人都聽見了。" },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "另外，根據公路單位通報，鳴海山路目前維持開放，但視雨勢發展，可能在傍晚前後實施預警性管制。請同學們不要自行前往山區，傍晚後請勿離開校園主要活動區域。若有家長需提前接送，請至校門口指揮站登記。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廣播結束後，教室裡安靜了兩秒。然後有人開始低聲討論，聲音像水一樣慢慢漲起來。有人在問山路什麼時候會封，有人在擔心晚上的閉幕典禮能不能直播，有人在跟旁邊的人說「我媽剛打電話來叫我別回家了」。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)山路可能會封。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果山路封了，這裡就變成一座島。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉頭看向窗外。教室在三樓，視線可以越過操場邊緣的樹叢看到更遠的地方。遠處的山脊線已經被低雲吃掉了一半，灰色的雲層壓得很低，低到像是要碰到教學樓的屋頂。天空不是黑的，而是一種很深的鉛灰色，像是有人把所有顏色都抽走了，只留下金屬的冷光。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "隔壁班的老師走進了教室。他手裡拿著一疊影印紙，臉上的表情是想讓人安心的那種——嘴角微微上揚，眉頭刻意放鬆，像一個人在暴風雨前告訴你「一切都好」。" },
    { characterId: CharacterId.Student, character: "同學", dialogue: "老師，山路真的會封嗎？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "老師把影印紙放在講桌上，拍了拍手上的粉筆灰。" },
    { characterId: CharacterId.Student, character: "同學", dialogue: "不用太緊張。學校這邊有警力駐守，也有充足的緊急物資。你們看，下午校門口又多了兩輛巡邏車。上面有安排的，不會讓你們出事。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)警力駐守。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔就是警察。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他今天一整天都在指揮室附近。他知道所有的巡邏路線、所有的監控位置、所有的門禁安排。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果校園裡有危險，警察應該是最安全的力量。但如果危險來自警察呢？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個念頭閃過腦海的時候，他自己都覺得荒謬。邵叔從小看他長大，逢年過節會來家裡，父親出事之後是邵叔幫他處理的後事手續。邵叔不是壞人。邵叔不可能傷害他。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)可是他看到那條訊息的時候，表情變了一瞬。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那一瞬間很短，短到幾乎可以忽略。但我看見了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在意「相機」這兩個字。不是因為警察的職業直覺，是因為他知道那是什麼。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低頭看了一眼手機。螢幕上顯示的是那個陌生號碼——早上收到訊息的號碼。他打開了搜尋引擎，把號碼輸進去，按下搜尋。結果頁面跳出來，全部是「無相關資訊」「此號碼未登記於公開資料庫」之類的回覆。他又試了一個反向查號的網站，填入號碼，驗證碼，等待。結果是一樣的。什麼都查不到。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個查不到的號碼。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是普通的預付卡，就是經過特殊處理的。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)發訊息的人不想要被找到。或者，不想要被輕易找到。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他鎖了螢幕，把手機放回口袋。窗外的雨更大了。雨滴打在窗框上的聲音從「嗒嗒嗒」變成了一片連續的「沙沙沙」，像有人在用砂紙打磨整個世界。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她知道訊息的事。她知道鐘樓。她知道相機。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她要嘛是發訊息的人，要嘛和發訊息的人有聯繫。不管哪一種，她都是目前唯一一條可以追的線。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從座位上站起來。椅子在地面上拖出一聲短促的摩擦音，前排有個人回頭看了他一眼，然後又轉回去了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走出教室，穿過走廊。走廊的窗戶是開著的，風從外面灌進來，帶著雨水的味道和泥土的腥氣。走廊的地面是濕的——有人的鞋底把雨水帶進來了，從大門口一路延伸到樓梯間，像一條蜿蜒的深色痕跡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "文檔組的集合點在行政樓一樓的會議室。他知道的，因為校慶活動手冊上印著每一組的集合地點。他走下樓梯，穿過連接教學樓和行政樓的天橋。天橋的兩側是玻璃窗，雨水在玻璃上流成無數條細小的河流，讓外面的世界變成一幅模糊的水彩畫。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "行政樓一樓的走廊比教學樓安靜。會議室的門是半開的，裡面傳出低低的說話聲和偶爾的笑聲。他走到門口，往裡面看了一眼。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "會議室裡坐了七八個人，有學生也有老師，桌上散著筆電、筆記本和幾台相機。有人正在整理照片檔案，有人在核對活動時程表。看起來是一個正常的工作會議。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "許星棠呢。" },
    { characterId: CharacterId.Student, character: "同學", dialogue: "星棠？她下午沒來啊。好像中午之後就沒看到她了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)沒來。" },
    { characterId: CharacterId.Student, character: "同學", dialogue: "她是攝影組的，可能在外面拍東西吧。你要留話嗎？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不用了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他退離會議室門口。走回走廊的時候，他的步伐比來的時候快了一點。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她不在集合點。中午之後就沒有人看到她。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)中午。那是我遇到她的時候。長廊。她在拍邵叔和林主任。然後韓越把她叫走了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)之後她就消失了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在行政樓的走廊裡，兩邊是灰白色的牆壁，頭頂是嗡嗡作響的日光燈。走廊的盡頭是一扇通往戶外的玻璃門，門外面是雨，雨的後面是鉛灰色的天空，天空的下面是被雨吞掉一半的校園。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她去哪了？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個在拍大人行蹤的人，一個知道匿名訊息的人，一個警告我不要靠近鐘樓的人。然後她消失了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她是躲起來了，還是被叫走了？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)韓越說「妳不能再一個人去」。他是在阻止她做某件事。她要做的那件事，是不是就是讓她消失的原因？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在走廊的牆上，後腦勺抵著冰涼的灰白色油漆面。雨聲從玻璃門的縫隙裡鑽進來，在空蕩的走廊裡產生一種輕微的回音，像有人跟在他後面走。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)冷靜。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)把所有的事情排在一起看。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上七點十二分，收到匿名訊息。內容是：今晚 22:22，鐘樓會停電。不要上去。不要把相機交給任何大人。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)九點半，校史館。林主任抽走一張舊照片。照片裡有我、爸爸、邵叔、一個我不認識的女人。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十一點，邵叔出現。他看到訊息的時候表情變了一瞬。他問我是否想起小時候的事。他對「相機」兩個字看得特別久。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十二點半，許星棠。她在拍指揮室、拍邵叔、拍林主任。她知道訊息，她警告我不要去鐘樓，她提到相機。然後她說「忘了我說的」。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)韓越出現，帶走了她。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在三點。廣播說山路可能會封。學生不要離開主要活動區。老師說有警察和物資，不用擔心。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠消失了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這些事情像散落在桌上的拼圖碎片。每一片都有一個角、一個顏色、一個模糊的圖案。但我看不到完整的圖。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我只知道一件事：所有的碎片都指向同一個晚上。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他離開行政樓，從側門走出去。雨打在他的肩膀和頭頂，他沒有撐傘，外套的肩線在幾秒之內就濕透了。他沿著教學樓和圖書館之間的通道往前走，經過了一排被雨水打得低垂的杜鵑花叢，花叢的葉片上有水珠在滾動，像透明的昆蟲。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校園主廣場上幾乎沒有人了。上午的熱鬧像潮水一樣退去，只剩下幾個穿著雨衣的志工在收拾帳篷，以及一兩撥撐著傘快步走過的家長。操場邊的臨時舞台已經用繩索加固過了，防水布在風裡啪啪作響，像一面被反覆摑掌的旗。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在通道的出口處，視線穿過雨幕看向遠處。鐘樓在那裡。灰色的、沉默的、不動的。雨把它的輪廓洗得模糊，像一個正在融化的影子。頂上的鐘面朝著天空，指針看不見，但你知道它在走。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息、許星棠、邵叔。三個不同的人、三種不同的態度，但都指向同一個地方。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今晚會發生什麼？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我不知道。但我知道我不會待在宿舍裡等。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨繼續下。他轉身走回教學樓的方向，外套濕透了，貼在背上，冰涼的水沿著脊椎往下淌。走廊裡的日光燈在雨天的昏暗中顯得格外白、格外冷，把每一個人的臉都照得毫無血色。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遠處，廣播又響了。這一次是播放校慶的背景音樂，一首管弦樂的進行曲，從喇叭裡傳出來，被雨聲和風聲切割成斷斷續續的片段。聽起來不像慶典，更像一場不情願的告別。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)天氣在變壞。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)山路會封。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所有人都被留在校園裡。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而校園裡最安全的人，也許就是最危險的人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走回教室，在座位上坐下。窗外的雨聲更大了，大到像有人在用拳頭擂門。他拿出手機，解鎖，看了一眼時間。十五點四十七分。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "距離天黑還有不到三個小時。距離二十二點二十二分還有六個半小時。距離什麼東西發生——或者什麼東西結束——他說不清楚。但那種感覺在那裡。像一根針紮在皮膚下面，不痛，但你知道它在那裡。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這座校園正在關上它的門。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而我還不知道，我是被保護在裡面，還是被鎖在裡面。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外，鐘樓在雨中沉默。它不會回答任何人的問題。它只是站在那裡，等著指針走到那個位置。" },
];
